```go
package main

import (
    "context"
    "flag"
    "fmt"
    "log"
    "net"
    "net/http"
    "net/http/httputil"
    "net/url"
    "strings"
    "sync"
    "sync/atomic"
    "time"
)

type contextKey int

const (
    Attempts contextKey = iota
    Retry
)

type Backend struct {
    URL          *url.URL
    Alive        bool
    mux          sync.RWMutex
    ReverseProxy *httputil.ReverseProxy
}

func (b *Backend) SetAlive(alive bool) {
    b.mux.Lock()
    b.Alive = alive
    b.mux.Unlock()
}

func (b *Backend) IsAlive() bool {
    b.mux.RLock()
    defer b.mux.RUnlock()
    return b.Alive
}

type ServerPool struct {
    backends []*Backend
    current  uint64
}

func (s *ServerPool) AddBackend(b *Backend) {
    s.backends = append(s.backends, b)
}

func (s *ServerPool) NextIndex() int {
    return int(atomic.AddUint64(&s.current, 1) % uint64(len(s.backends)))
}

func (s *ServerPool) GetNextPeer() *Backend {
    next := s.NextIndex()
    l := len(s.backends) + next
    for i := next; i < l; i++ {
        idx := i % len(s.backends)
        if s.backends[idx].IsAlive() {
            if i != next {
                atomic.StoreUint64(&s.current, uint64(idx))
            }
            return s.backends[idx]
        }
    }
    return nil
}

func (s *ServerPool) MarkBackendStatus(backendURL *url.URL, alive bool) {
    for _, b := range s.backends {
        if b.URL.String() == backendURL.String() {
            b.SetAlive(alive)
            return
        }
    }
}

func (s *ServerPool) HealthCheck() {
    for _, b := range s.backends {
        alive := isBackendAlive(b.URL)
        b.SetAlive(alive)
        status := "up"
        if !alive {
            status = "down"
        }
        log.Printf("%s [%s]\n", b.URL, status)
    }
}

var serverPool ServerPool

func GetAttemptsFromContext(r *http.Request) int {
    if v, ok := r.Context().Value(Attempts).(int); ok {
        return v
    }
    return 0
}

func GetRetryFromContext(r *http.Request) int {
    if v, ok := r.Context().Value(Retry).(int); ok {
        return v
    }
    return 0
}

func lb(w http.ResponseWriter, r *http.Request) {
    attempts := GetAttemptsFromContext(r)
    if attempts > 3 {
        log.Printf("%s(%s) Max attempts reached\n", r.RemoteAddr, r.URL.Path)
        http.Error(w, "Service not available", http.StatusServiceUnavailable)
        return
    }
    peer := serverPool.GetNextPeer()
    if peer != nil {
        peer.ReverseProxy.ServeHTTP(w, r)
        return
    }
    http.Error(w, "Service not available", http.StatusServiceUnavailable)
}

func isBackendAlive(u *url.URL) bool {
    conn, err := net.DialTimeout("tcp", u.Host, 2*time.Second)
    if err != nil {
        log.Println("Site unreachable:", err)
        return false
    }
    defer conn.Close()
    return true
}

func healthCheck() {
    t := time.NewTicker(20 * time.Second)
    for {
        select {
        case <-t.C:
            log.Println("Starting health check...")
            serverPool.HealthCheck()
            log.Println("Health check completed")
        }
    }
}

func main() {
    var serverList string
    var port int
    flag.StringVar(&serverList, "backends", "", "Comma-separated backend URLs")
    flag.IntVar(&port, "port", 3000, "Port to serve on")
    flag.Parse()

    if serverList == "" {
        log.Fatal("Please provide backends via --backends")
    }

    for _, tok := range strings.Split(serverList, ",") {
        serverURL, err := url.Parse(strings.TrimSpace(tok))
        if err != nil {
            log.Fatal(err)
        }
        proxy := httputil.NewSingleHostReverseProxy(serverURL)
        proxy.ErrorHandler = func(w http.ResponseWriter, r *http.Request, e error) {
            log.Printf("[%s] %s\n", serverURL.Host, e.Error())
            retries := GetRetryFromContext(r)
            if retries < 3 {
                select {
                case <-time.After(10 * time.Millisecond):
                    ctx := context.WithValue(r.Context(), Retry, retries+1)
                    proxy.ServeHTTP(w, r.WithContext(ctx))
                }
                return
            }
            serverPool.MarkBackendStatus(serverURL, false)
            attempts := GetAttemptsFromContext(r)
            ctx := context.WithValue(r.Context(), Attempts, attempts+1)
            lb(w, r.WithContext(ctx))
        }
        serverPool.AddBackend(&Backend{URL: serverURL, Alive: true, ReverseProxy: proxy})
        log.Printf("Configured backend: %s\n", serverURL)
    }

    server := http.Server{
        Addr:    fmt.Sprintf(":%d", port),
        Handler: http.HandlerFunc(lb),
    }
    go healthCheck()
    log.Printf("Load Balancer started at :%d\n", port)
    log.Fatal(server.ListenAndServe())
}
